class Solution:
    def findNumberOfLIS(self, nums):
        n = len(nums)
        if n == 0:
            return 0
        length = [1] * n
        count = [1] * n
        for j in range(n):
            for i in range(j):
                if nums[i] < nums[j]:
                    if length[i] + 1 > length[j]:
                        length[j] = length[i] + 1
                        count[j] = count[i]
                    elif length[i] + 1 == length[j]:
                        count[j] += count[i]
        best = max(length)
        return sum(c for l, c in zip(length, count) if l == best)

