var findNumberOfLIS = function(nums) {
    const n = nums.length;
    if (n === 0) return 0;
    const length = new Array(n).fill(1);
    const count = new Array(n).fill(1);
    let best = 1;
    for (let j = 0; j < n; j++) {
        for (let i = 0; i < j; i++) {
            if (nums[i] < nums[j]) {
                if (length[i] + 1 > length[j]) {
                    length[j] = length[i] + 1;
                    count[j] = count[i];
                } else if (length[i] + 1 === length[j]) {
                    count[j] += count[i];
                }
            }
        }
        if (length[j] > best) best = length[j];
    }
    let total = 0;
    for (let k = 0; k < n; k++) if (length[k] === best) total += count[k];
    return total;
};
